INSERT INTO course_chunks (class_id, source, topic_tag, content) VALUES (1, 'lecture', 'Sessions', 'Sessions Agenda • Sessions • First-party cookies • Third-party cookies • Example from project 2 2 What are sessions? • How a website knows multiple requests come from the same user • Example: login • Log in on one web page • Site remembers you are logged in on other pages • Example: shopping cart • Cart persists across pages 3 Problem: Stateless HTTP • HTTP is stateless • No memory between requests or connections 4 What are sessions? • How a website knows multiple requests come from the same user 5 Amazon Server Cart 1 Cart 2 Client 1 Client 2 What are sessions? • How a website knows multiple requests come from the same user 6 Amazon Server Cart 1 Cart 2 Client 1 Client 2 Which Cart? What are sessions? • How a website knows multiple requests come from the same user 7 Amazon Server Cart 1 Cart 2 Client 1 Client 2 Same Cart? What are sessions? • How a website knows multiple requests come from the same user Can we use the HTTP request? 8 Amazon Server Cart 1 Cart 2 Client 1 Client 2 Problem: Stateless HTTP • HTTP is stateless • No memory between requests or connections • Solution: Include extra “ID” data with every HTTP request • Usually implemented with cookies 9 What are sessions? • How a website knows multiple requests come from the same user 10 Amazon Server Cart 1 Cart 2 Client 1 Client 2 Login ID John1 Login ID: Smith2 Session IDs Cart # John1 Cart1 What are sessions? • How a website knows multiple requests come from the same user 11 Amazon Server Cart 1 Cart 2 Client 1 Client 2 Login ID: John1 Login ID: Smith2 Session IDs Cart # John1 Cart1 Server Name ID Amazon John1 What are sessions? • How a website knows multiple requests come from the same user 12 Amazon Server Cart 1 Cart 2 Client 1 Client 2 Login ID: John1 Login Id: Smith2 Session ID Cart # John1 Cart1 Server Name ID Amazon John1 What are sessions? • How a website knows multiple requests come from the same user 13 Amazon Server Cart 1 Cart 2 Client 1 Client 2 Login ID: John1 Login ID: Smith2 Session IDs Cart # John1 Cart1 Server Name ID Amazon John1 What are sessions? • How a website knows multiple requests come from the same user 14 Amazon Server Cart 1 Cart 2 Client 1 Client 2 Login ID: John1 Login ID: Smith1 Session IDs Cart # John1 Cart1 Smith1 Cart2 Server Name ID Amazon John1 Server Name ID Amazon Smith1 What are sessions? • How a website knows multiple requests come from the same user 15 Amazon Server Cart 1 Cart 2 Client 1 Client 2 Login ID: John1 Login ID: Smith1 Session IDs Cart # John1 Cart1 Smith1 Cart2 Server Name ID Amazon John1 Server Name ID Amazon Smith1 What are sessions? • How a website knows multiple requests come from the');
INSERT INTO course_chunks (class_id, source, topic_tag, content) VALUES (1, 'lecture', 'Sessions', 'website knows multiple requests come from the same user 13 Amazon Server Cart 1 Cart 2 Client 1 Client 2 Login ID: John1 Login ID: Smith2 Session IDs Cart # John1 Cart1 Server Name ID Amazon John1 What are sessions? • How a website knows multiple requests come from the same user 14 Amazon Server Cart 1 Cart 2 Client 1 Client 2 Login ID: John1 Login ID: Smith1 Session IDs Cart # John1 Cart1 Smith1 Cart2 Server Name ID Amazon John1 Server Name ID Amazon Smith1 What are sessions? • How a website knows multiple requests come from the same user 15 Amazon Server Cart 1 Cart 2 Client 1 Client 2 Login ID: John1 Login ID: Smith1 Session IDs Cart # John1 Cart1 Smith1 Cart2 Server Name ID Amazon John1 Server Name ID Amazon Smith1 What are sessions? • How a website knows multiple requests come from the same user 16 Amazon Server Cart 1 Cart 2 Client 1 Client 2 Session IDs Cart # 123 Cart1 452 Cart2 Server Name ID Amazon 123 Server Name ID Amazon 452 Session Cookies Agenda • Sessions • First-party cookies • Third-party cookies • Example from project 2 17 Cookies • Cookies are small pieces of data stored in the browser • Carry state between HTTP requests • Contain key/value pairs 18 Example: cookies in Chrome • Browsing to chrome://settings/siteData • You can inspect cookies on your own browser 19 Example: cookies in Chrome • Browse to • Settings / Advanced / Content settings / Cookies / See all cookies 20 Example: shopping cart • Browse to • Add something to the cart 21 Example: shopping cart • Again, browse to • Cart has one item, even though we’re on a different page 22 Example: shopping cart • Clear cookies using the developer console 23 Example: shopping cart • Again, browse to • Cart appears empty because the session cookie is gone 24 Example: facebook log in • Log in Facebook (or any other web site) • Clear the Facebook cookies using the developer console • Visit facebook.com again • You’re no longer logged in 25 Cookie content • Name: chosen by the server • Value: chosen by the server (often encrypted) • Domain: which site can read it • Path: specifies scope of cookie • / vs. /cart/ or whatever • Expiration: when browser deletes it • Secure: is how cookie may be transmitted 26 Cookie rules • Cookies only over-writable by same domain and path • Enforced by browser • Store a username, session ID, etc. in the cookie • Use session ID or username to do a database lookup • Shopping card content 27 Cookie transfer • Set by server • Sent by client, but never edited • Either side can delete/ignore cookies • Sent as part of HTTP headers 28 Cookie overhead • Cookies add to HTTP overhead • Best practice is to store a small amount of data in the cookie • Use that data to');
INSERT INTO course_chunks (class_id, source, topic_tag, content) VALUES (1, 'lecture', 'Sessions', 'no longer logged in 25 Cookie content • Name: chosen by the server • Value: chosen by the server (often encrypted) • Domain: which site can read it • Path: specifies scope of cookie • / vs. /cart/ or whatever • Expiration: when browser deletes it • Secure: is how cookie may be transmitted 26 Cookie rules • Cookies only over-writable by same domain and path • Enforced by browser • Store a username, session ID, etc. in the cookie • Use session ID or username to do a database lookup • Shopping card content 27 Cookie transfer • Set by server • Sent by client, but never edited • Either side can delete/ignore cookies • Sent as part of HTTP headers 28 Cookie overhead • Cookies add to HTTP overhead • Best practice is to store a small amount of data in the cookie • Use that data to do a database lookup on the server side 29 Secure (Encrypted) cookie transfer • If I have your cookies, I can steal your session • To the server, I look just like you! • Prevent this by sending cookies only over HTTPS 30 Signed or Encrypted cookie values • If the client has a copy of cookies set by the server, then the client can manipulate the server • Prevent this with signed or encrypted cookie content • Only the server can verify or decrypt 31 Agenda • Sessions • First-party cookies • Third-party cookies • Example from project 2 32 Third-party cookies • Goal: track a user across different websites • Useful for advertisers to learn what sites you visit 33 Where they come from? • Page can load content from many domains • Scripts, images, etc. • These 3rd-party domains can set and read cookies • Example: nytimes.com <html> <head> <script src=" type="text/javascript" > </script> </head> <body> <img src=" </body> </html> 34 Cookie domains • Cookies always belong to a domain • First-party cookie: same domain as the page you are on • Third-party cookie: different domain • Example from nytimes.com 35 Example: Google advertising cookies • Advertising cookie name IDE and is stored under the domain doubleclick.net. • Set when visiting many non-Google websites • • Example: visit nytimes.com and view cookies: 36 Example: Google advertising cookies • Excerpt from nytimes.com HTML source <html> <body> ... <script> function placeGpt() { var gptScript = document.createElement(''script''); gptScript.src = ''//securepubads.g.doubleclick.net/tag/js/gpt.js''; document.head.appendChild(gptScript); } placeGpt() </script> </body> </html> 37 Example: First Visit flow (nytimes.com) • You visit nytimes.com • Browser gets HTML + JavaScript • JavaScript sends request to doubleclick.net • Request includes current site (nytimes.com) • doubleclick.net creates a unique ID • Server responds with Set-Cookie for doubleclick.net 38 Example: Second visit flow (bloomberg.com) • You visit bloomberg.com • Page loads JavaScript from doubleclick.net • Browser sends request to doubleclick.net • Includes existing cookie (your ID) • Includes current site (bloomberg.com) • doubleclick.net recognizes you • Database updated with new site visit 39 Example: Google advertising Cookies doubleclick.net client (browser) nytimes.com');
INSERT INTO course_chunks (class_id, source, topic_tag, content) VALUES (1, 'lecture', 'Sessions', 'cookie name IDE and is stored under the domain doubleclick.net. • Set when visiting many non-Google websites • • Example: visit nytimes.com and view cookies: 36 Example: Google advertising cookies • Excerpt from nytimes.com HTML source <html> <body> ... <script> function placeGpt() { var gptScript = document.createElement(''script''); gptScript.src = ''//securepubads.g.doubleclick.net/tag/js/gpt.js''; document.head.appendChild(gptScript); } placeGpt() </script> </body> </html> 37 Example: First Visit flow (nytimes.com) • You visit nytimes.com • Browser gets HTML + JavaScript • JavaScript sends request to doubleclick.net • Request includes current site (nytimes.com) • doubleclick.net creates a unique ID • Server responds with Set-Cookie for doubleclick.net 38 Example: Second visit flow (bloomberg.com) • You visit bloomberg.com • Page loads JavaScript from doubleclick.net • Browser sends request to doubleclick.net • Includes existing cookie (your ID) • Includes current site (bloomberg.com) • doubleclick.net recognizes you • Database updated with new site visit 39 Example: Google advertising Cookies doubleclick.net client (browser) nytimes.com bloomberg.com Cookies:DB Example: Google advertising Cookies doubleclick.net client (browser) nytimes.com bloomberg.com Cookies: doubleclick.net client_id = 123 DB client 123 → nytimes.com First visit: cookie created Example: Google advertising Cookies doubleclick.net client (browser) nytimes.com bloomberg.com Cookies: doubleclick.net client_id = 123 DB client 123 → nytimes.com Example: Google advertising Cookies doubleclick.net client (browser) nytimes.com bloomberg.com Cookies: doubleclick.net client_id = 123 DB client 123 → nytimes.com bloomberg.com Second site: same cookie reused Who uses third-party cookies? • Companies that sell ads directly • Google and Facebook (obviously) • Companies that sell information about you • Acxiom "one of the biggest companies you''ve never heard of" ($1B+) • “If you''re not paying for the product, then you are the product” • That''s mostly how the business side of the web is structured 44 Agenda • Sessions • First-party Cookies • Third-party cookies • Example from project 2 45 Cookie example 46 Key idea: cookie is a collection of key/value pairs. Flask provides them in a dictionary called flask.session if "user" in flask.session: user = flask.session["user"] else: flask.session["user"] = "smith" Test if key exists Get key/value Set key/value Cookie example 47 import flask app = flask.Flask(__name__) app.secret_key = b’…secure random bytes…'' @app.route(''/'') def index(): if "user" in flask.session: user = flask.session["user"] return "<html><body>Hello {user}</body></html>“ else: flask.session["user"] = “smith" return "<html><body>Logging in ...</body></html>" if __name__ == ''__main__'': app.run() Key idea: cookie is a collection of key/value pairs. Flask provides them in a dictionary calledflask.session Run the cookie example • Start server $ python3 test.py • Browse to • See encrypted cookie in developer console 48 Cookie encryption key • Goal: prevent users from forging session cookies • The encryption key must be: • Random • Unpredictable • Cryptographically secure. • Generate a Python string $ python3 -c "import os; print(os.urandom(24))“ b''uAy\x9d\x08[\x12\x8d\x9d\x1f\xbar\x86A\x9fpQy4\x05)v04'' 49 Cookie example 50 import flask app = flask.Flask(__name__) app.secret_key = b''uAy\x9d\x08[\x12\x8d\x9d\x1f\xbar\x86A\x9fpQy4\x05)v04'' @app.route(''/'') def index(): if "user" in flask.session: user = flask.session["user"] return f"<html><body>Hello {user}</body></html>“ else: flask.session["user"] = “smith" return "<html><body>Logging in ...</body></html>" if __name__ == ''__main__'': app.run() Key idea: cookie is a collection of key/value pairs. Flask provides them in a dictionary calledflask.session Test');
INSERT INTO course_chunks (class_id, source, topic_tag, content) VALUES (1, 'lecture', 'Sessions', '"user" in flask.session: user = flask.session["user"] return "<html><body>Hello {user}</body></html>“ else: flask.session["user"] = “smith" return "<html><body>Logging in ...</body></html>" if __name__ == ''__main__'': app.run() Key idea: cookie is a collection of key/value pairs. Flask provides them in a dictionary calledflask.session Run the cookie example • Start server $ python3 test.py • Browse to • See encrypted cookie in developer console 48 Cookie encryption key • Goal: prevent users from forging session cookies • The encryption key must be: • Random • Unpredictable • Cryptographically secure. • Generate a Python string $ python3 -c "import os; print(os.urandom(24))“ b''uAy\x9d\x08[\x12\x8d\x9d\x1f\xbar\x86A\x9fpQy4\x05)v04'' 49 Cookie example 50 import flask app = flask.Flask(__name__) app.secret_key = b''uAy\x9d\x08[\x12\x8d\x9d\x1f\xbar\x86A\x9fpQy4\x05)v04'' @app.route(''/'') def index(): if "user" in flask.session: user = flask.session["user"] return f"<html><body>Hello {user}</body></html>“ else: flask.session["user"] = “smith" return "<html><body>Logging in ...</body></html>" if __name__ == ''__main__'': app.run() Key idea: cookie is a collection of key/value pairs. Flask provides them in a dictionary calledflask.session Test if key exists Get key/value Set key/value Cookie encryption key 51 import flask app = flask.Flask(__name__) app.secret_key = b''uAy\x9d\x08[\x12\x8d\x9d\x1f\xbar\x86A\x9fpQy4\x05)v04'' # ... • Session cookies are encrypted • Ony the server knows the encryption key • Without encryption, anyone could pretend to be any one Summary • A session helps a server tell the difference between clients • Sessions are implemented with cookies • Cookies are set by one site''s server and stored by the client''s browser • Site''s cookies are sent by the client with every request to the site • Third-party cookies are used for tracking users across different sites 52 Further reading • Good reference on first-party cookies • Good reference on third-party party_cookies 53');
INSERT INTO course_chunks (class_id, source, topic_tag, content) VALUES (1, 'lecture', 'Encryption', 'Encryption Agenda • Overview • Symmetric encryption • Asymmetric encryption • Public key infrastructure • Cryptographic hash functions • Social impacts of encryption • Summary 2 Network communication • Two parties communicate over the internet • Example: visiting amazon.com • Let’s imagine I’m sending my credit card info 3 Network message 4 Internet routers • How do we connect all the computers on the internet? • A router forwards data from one network to the next • Usually a purpose-built Linux computer with multiple network connections 5 Internet routers 6 Neither sender nor receiver control the routers in the middle! Network security • Two parties communicate over a network • Assume powerful adversary • Can read (eavesdrop on) all data transmitted • Can modify or delete any data • Can inject new data • Communication: What properties would you like? 7 Desirable properties • Confidentiality • Adversary should not understand message • Sender authenticity • Message is really from the purported sender • Message integrity • Message not modified between send and receive • Freshness • Message was sent “recently” • Anonymity • Attacker should not know that we are communicating 8 Encryption as a function • Plaintext message string • Encryption key (Kenc ) • Decryption key (Kdec ) • ciphertext = encrypt (plaintext, Kenc) • plaintext = decrypt (ciphertext, Kdec) 9 Encryption in words • Encryption applies a reversible mathematical function to data, producing unreadable output • Decryption recovers the original data from the unreadable encryption-output • The key is secret 10 Agenda • Overview • Symmetric encryption • Asymmetric encryption • Public key infrastructure • Cryptographic hash functions • Summary 11 Symmetric encryption • Key controls how data is encrypted and decrypted • Both sides use the same key • One side uses the key to encrypt • Other side uses the key to decrypt • This is called symmetric encryption 12 Symmetric Encryption • Advantage: fast to compute • Disadvantage: how do you securely share the key? 13 AES • "Advanced Encryption Standard" • Most common symmetric cipher • Won''t go into AES details in this class • Old symmetric cipher: DES • Now insecure 14 Symmetric encryption summary • One key for encrypt and decrypt • Fast to compute • Symmetric encryption provides confidentiality • Adversary should not understand message • Symmetric encryption can provide message integrity • Message was not modified between send and receive 15 Agenda • Overview • Symmetric encryption • Asymmetric encryption • Public key infrastructure • Cryptographic hash functions • Summary 16 Asymmetric encryption • Asymmetric encryption uses a pair of keys • Each party has: • A public key, which is published freely • A private key, which is shared with no one • A message encrypted with one key can be decrypted with the other • You can''t derive one key from the other 17 Confidentiality • Asymmetric encryption provides confidentiality • Adversary should not understand message • Encrypt with public key, decrypt with private key • Anyone');
INSERT INTO course_chunks (class_id, source, topic_tag, content) VALUES (1, 'lecture', 'Encryption', 'class • Old symmetric cipher: DES • Now insecure 14 Symmetric encryption summary • One key for encrypt and decrypt • Fast to compute • Symmetric encryption provides confidentiality • Adversary should not understand message • Symmetric encryption can provide message integrity • Message was not modified between send and receive 15 Agenda • Overview • Symmetric encryption • Asymmetric encryption • Public key infrastructure • Cryptographic hash functions • Summary 16 Asymmetric encryption • Asymmetric encryption uses a pair of keys • Each party has: • A public key, which is published freely • A private key, which is shared with no one • A message encrypted with one key can be decrypted with the other • You can''t derive one key from the other 17 Confidentiality • Asymmetric encryption provides confidentiality • Adversary should not understand message • Encrypt with public key, decrypt with private key • Anyone can encrypt • ciphertext = encrypt (plaintext, Kalice_public) • Only Alice can decrypt • plaintext = decrypt (ciphertext, Kalice_private) • Sometimes called sealing a message 18 Sender authenticity • Asymmetric encryption provides sender authenticity • Message is really from the purported sender • Encrypt with private key, decrypt with public key • Only Alice can encrypt • ciphertext = encrypt (plaintext, Kalice_private) • Anyone can decrypt • plaintext = decrypt (ciphertext, Kalice_public) • Sometimes called signing a message 19 Combining properties • We can combine the two previous examples to gain all three desirable properties • Confidentiality • Adversary should not understand message • Sender authenticity • Message is really from the purported sender • Message integrity • Message not modified between sending and receiving 20 Combining properties Alice sends a message to Bob 1. sealed_ciphertext = encrypt(plaintext, K_bob_public) 2. signed_ciphertext = encrypt(sealed_ciphertext, K_alice_private) Bob receives message from Alice 1. ciphertext = decrypt(signed_ciphertext, K_alice_public) • Verify signed ciphertext, anyone can do this 2. plaintext = decrypt(ciphertext, K_bob_private) • Decrypt ciphertext, only Bob can do this 21 How does asymmetric encryption work? • Public key cryptography relies on trapdoor functions • A function that is: • Easy to compute in one direction • Hard to reverse without special information • “Easy” and “hard” are meant computationally • Poor trapdoor functions • Add 2 • Multiply by 3 • Finding good trapdoor functions in difficult • The most widely used ones are based on prime factorization 22 Trapdoor functions • n = p*q, where p and q are large primes • Given p and q, easy to compute n • Given n, very hard to find p and q • Public, private keys are derived from the original primes • Only the product n is made public • Recovering the original primes from n is computationally infeasible 23 Asymmetric encryption examples • Encrypted email • Only the recipient can decrypt • SSH keys • GitHub knows it’s you when you git push • Verified commits on GitHub • Real developer modified code • Signal and WhatsApp 24 Agenda • Overview • Symmetric');
INSERT INTO course_chunks (class_id, source, topic_tag, content) VALUES (1, 'lecture', 'Encryption', 'direction • Hard to reverse without special information • “Easy” and “hard” are meant computationally • Poor trapdoor functions • Add 2 • Multiply by 3 • Finding good trapdoor functions in difficult • The most widely used ones are based on prime factorization 22 Trapdoor functions • n = p*q, where p and q are large primes • Given p and q, easy to compute n • Given n, very hard to find p and q • Public, private keys are derived from the original primes • Only the product n is made public • Recovering the original primes from n is computationally infeasible 23 Asymmetric encryption examples • Encrypted email • Only the recipient can decrypt • SSH keys • GitHub knows it’s you when you git push • Verified commits on GitHub • Real developer modified code • Signal and WhatsApp 24 Agenda • Overview • Symmetric encryption • Asymmetric encryption • Public key infrastructure • Cryptographic hash functions • Summary 25 How do you distribute public keys? • Problem: How do you get a public key? • What if the public key is faked? • Solution: The Public Key Infrastructure (PKI) distributes public keys safely, via certificates • A certificate is signed document that contains org’s public key 26 Public key infrastructure • Asymmetric cryptography depends on sharing public keys • How do you know that Amazon''s public key actually comes from Amazon? 27 Public key infrastructure • Asymmetric cryptography depends on sharing public keys • How do you know that Amazon''s public key actually comes from Amazon? 28 Amazon 0X3dc Evil 0Xtca Fake Public Key You 0Xtca Evil has the matching Private Key Certificate Authorities • Verify identities and public keys. • A certificate is signed document that contains org’s name and public key • Your browser has a copy of all certifications. 29 Asymmetric encryption is slow • Problem: Asymmetric encryption is slow • Symmetric is fast • Solution: • Asymmetric to exchange symmetric key • Symmetric to encrypt all messages • That''s HTTPS (aka TLS/SSL) 30 HTTPS • Little public-key-encrypted data • Browser verifies validity of certificate 31 AES AES HTTPS • Transport Layer Security / Secure Sockets Layer • Commonly, https:// • Encryption of all content that goes into TCP payload 32 HTTPS example 1. Hello • Client sends hello message to server • Includes supported cipher algorithms and TLS version • Server sends hello message to client • Includes selected cipher algorithm and TLS version 33 HTTPS example 2. Certificate exchange • Server proves its identity to the client • Server sends SSL certificate and public key • Client checks certificate against stored CAs 34 HTTPS example 3. Key exchange • Client generates random key to be used for later symmetric encryption • Client encrypts this key using the server''s public key • Remember, only the server will be able to decrypt this message using the server''s private key • After the shared key is established • All traffic is encrypted');
INSERT INTO course_chunks (class_id, source, topic_tag, content) VALUES (1, 'lecture', 'Encryption', 'verifies validity of certificate 31 AES AES HTTPS • Transport Layer Security / Secure Sockets Layer • Commonly, https:// • Encryption of all content that goes into TCP payload 32 HTTPS example 1. Hello • Client sends hello message to server • Includes supported cipher algorithms and TLS version • Server sends hello message to client • Includes selected cipher algorithm and TLS version 33 HTTPS example 2. Certificate exchange • Server proves its identity to the client • Server sends SSL certificate and public key • Client checks certificate against stored CAs 34 HTTPS example 3. Key exchange • Client generates random key to be used for later symmetric encryption • Client encrypts this key using the server''s public key • Remember, only the server will be able to decrypt this message using the server''s private key • After the shared key is established • All traffic is encrypted using fast symmetric encryption 35 Agenda • Overview • Symmetric encryption • Asymmetric encryption • Public key infrastructure • Cryptographic hash functions • Summary 36 Hashing passwords • How does the server verify your password? 37 Hashing passwords • How does the server verify your password? • Server stores usernames and passwords in the database • On login, compare the entered password with the stored one • If the database is stolen; all passwords are exposed 38 Username First Name Last Name Email Password Awdeorio Andrew DeOrio awdeorio@umich.edu Bob1pass ………. ………. ………. ………. ………. Hashing passwords • Better idea: store hashed passwords, not plain text • Server hashes the password using a one-way hash function • On login, hash the input password and compare hashes • If the database is stolen, attackers do not get passwords directly 39 Username First Name Last Name Email Password Awdeorio Andrew DeOrio awdeorio@umich.edu 1xcrd4588x9… ………. ………. ………. ………. ………. Example • Using SHA-512 to hash a password import hashlib m = hashlib.sha512(''bob1pass'') password_hash = m.hexdigest() print(password_hash) Af1bd47889bff89ccc889bc2aa61437c2ac90ee41161864 • You cannot recover the original password from the hash 40 Common passwords •The most common passwords are: • 123456 • 123456789 • qwerty • password • 11111111 • 12345678 • If an attacker gets my password database, how can they find which users used these passwords? 41 Cracking passwords • Brute force attack: try every possible character combination, hash it, see if it matches db entry • Dictionary attack: try all the words in the dictionary • Actually, many dictionaries • Example: John the Ripper, Hashcat, etc. 42 Rainbow tables • Pre-computed tables of hash • Example: download MD5 rainbow tables • Example: generate your own with RainbowCrack • Compute (or download) once, reuse many times • Can recover many passwords quickly 43 Hashed Password Password A347dsa4……. Bob1pass ………. ………. Protecting against cracking • Rainbow tables assume that all the passwords were "hashed the same way" • Use a salt to change how each password is hashed • Salt is a random number added to password before hashing • Each password is hashed with a different');
INSERT INTO course_chunks (class_id, source, topic_tag, content) VALUES (1, 'lecture', 'Encryption', '11111111 • 12345678 • If an attacker gets my password database, how can they find which users used these passwords? 41 Cracking passwords • Brute force attack: try every possible character combination, hash it, see if it matches db entry • Dictionary attack: try all the words in the dictionary • Actually, many dictionaries • Example: John the Ripper, Hashcat, etc. 42 Rainbow tables • Pre-computed tables of hash • Example: download MD5 rainbow tables • Example: generate your own with RainbowCrack • Compute (or download) once, reuse many times • Can recover many passwords quickly 43 Hashed Password Password A347dsa4……. Bob1pass ………. ………. Protecting against cracking • Rainbow tables assume that all the passwords were "hashed the same way" • Use a salt to change how each password is hashed • Salt is a random number added to password before hashing • Each password is hashed with a different salt • Store the salt with the password • Now you would need a different rainbow table for every password! 44 Protecting against rainbow tables Example: hash(Salt + password) hash(3cmypassword) => 0x39f8e.... •Different for each password •Store both salt and hashed passwords in DB. 45 Username First Name Last Name Email Salt Password Awdeorio Andrew DeOrio awdeorio@umich.edu 3c 0x39f8e… ………. ………. ………. ………. ………. Login verification • User logs in • Server reads password entry from database: sha512$<SALT>$<HASHED_PASSWORD> • Server computes sha512(<SALT> + input_password) • Server compares with stored hashed password <HASHED_PASSWORD> • If equal; login succeeds 46 Agenda • Overview • Symmetric encryption • Asymmetric encryption • Public key infrastructure • Cryptographic hash functions • Social impacts of encryption • Summary 47 Standard chat app Google ChatPerson A Person B hello encrypt with Google''s public key hello decrypt and store message encrypt with Person B''s public key hello decrypt message Issues • Google can read all messages • Law enforcement can subpoena messages without users knowing 49 Google ChatPerson A Person B hello hello hello Vulnerable spot! End-to-end encrypted chat 50 Signal485Person A Person B • Initial key agreement between users • Server only forwards encrypted messages • Diffie-Hellman creates a shared key only users know hello encrypt with key hello decrypt message server forwards message but can''t decrypt it End-to-end encrypted chat • Why not just use public/private keys? • If a private key leaked, all past messages can be decrypted • Decryption with private key is proof that a given user was the recipient of the messages • Real algorithm has some more safeguards 51 Policy response • FBI: calls it "warrant-proof encryption" • "warrant-proof encryption has created lawless digital spaces where bad actors are • sexually exploiting children, • conducting human trafficking, • sharing terrorist propaganda, • …" ( • Society must choose: • Strong privacy • Or easier law enforcement access 52 An interesting read • Dark Wire by Joseph Cox • Non-fiction • Anom end-to-end encrypted phone network • FBI backdoor added by developer 53 Agenda • Overview • Symmetric encryption • Asymmetric encryption');
INSERT INTO course_chunks (class_id, source, topic_tag, content) VALUES (1, 'lecture', 'Encryption', 'creates a shared key only users know hello encrypt with key hello decrypt message server forwards message but can''t decrypt it End-to-end encrypted chat • Why not just use public/private keys? • If a private key leaked, all past messages can be decrypted • Decryption with private key is proof that a given user was the recipient of the messages • Real algorithm has some more safeguards 51 Policy response • FBI: calls it "warrant-proof encryption" • "warrant-proof encryption has created lawless digital spaces where bad actors are • sexually exploiting children, • conducting human trafficking, • sharing terrorist propaganda, • …" ( • Society must choose: • Strong privacy • Or easier law enforcement access 52 An interesting read • Dark Wire by Joseph Cox • Non-fiction • Anom end-to-end encrypted phone network • FBI backdoor added by developer 53 Agenda • Overview • Symmetric encryption • Asymmetric encryption • Public key infrastructure • Cryptographic hash functions • Social impacts of encryption • Summary 54 Summary • Symmetric encryption • One key • Asymmetric encryption • Two keys • Cryptographic hash functions • No keys 55 Summary: desirable properties Today • Confidentiality • Adversary should not understand message • Sender authenticity • Message is really from the purported sender • Message integrity • Message not modified between send and receive 56 Summary: desirable properties Next time • Freshness • Message was sent “recently” Later • Anonymity • Attacker should not know that we are communicating • Dark Web Lecture 57');
INSERT INTO course_chunks (class_id, source, topic_tag, content) VALUES (1, 'lecture', 'Web Security', 'Web Security Agenda • Review • Network attacks • Web attacks 2 Review: Network message 3 Review: Internet routers • How do we connect all the computers on the internet? • A router forwards data from one network to the next • Usually a purpose-built Linux computer with multiple network connections 4 Review: Internet routers 5 Neither sender nor receiver control the routers in the middle! Review: network security • Two parties communicate over a network • Assume powerful adversary • Can read (eavesdrop on) all data transmitted • Can modify or delete any data • Can inject new data • Communication: What properties would you like? 6 Review: desirable properties • Confidentiality • Adversary should not understand message • Sender authenticity • Message is really from the purported sender • Message integrity • Message not modified between send and receive • Freshness • Message was sent “recently” • Anonymity • Attacker should not know that we are communicating 7 Review: encryption summary • Symmetric encryption • One key • Asymmetric encryption • Two keys • Cryptographic hash functions • No keys 8 Network attacks vs. web attacks • Network attacks (messages): target data in transit between client and server • Web attacks (servers): target the server-side application (e.g., our Flask app) 9 Agenda • Review • Network attacks • Web attacks 10 Agenda • Review • Network attacks • Eavesdropping • Replay • Masquerading • Man-in-the-middle • Web attacks 11 Eavesdropping • Capture a router and listen in 12 HTTPS helps with eavesdropping • Someone else listens to what you send • HTTPS encrypts the data, so they can’t understand it, but... 13 • NSA data center near SLC: "An article by Forbes estimates the storage capacity as between 3 and 12 exabytes in the near term, based on analysis of unclassified blueprints" (Wikipedia) 14 January 25, 2024 Governments and encryption • US had strict export controls on cryptography in 90s • US (big key sizes) vs. international (small key sizes, easy to break) • Government backdoor key embedded in pplications (Lotus Notes) 15 Data and law enforcement • Data collected about you can be searched with a warrant • Google knows everywhere you’ve been, so law enforcement does too (geofence warrant) • Lists of people who searched for topics • E-mails and chat messages • Google Transparency Report • 192,408 requests made to Google July-December 2022 16 End-to-end encryption • Some chat apps promise that the chat provider can’t read your messages • Technical details for WhatsApp: “WhatsApp Encryption Overview” paper • How do you know the app isn’t lying to you about the encryption status? 17 Agenda • Review • Network attacks • Eavesdropping • Replay • Masquerading • Man-in-the-middle • Web attacks 18 Replay attack • Memorize a message and send it multiple times 19 Replay attack • Memorize a message and send it multiple times 20 You myBank Evil Encrypt(Pay Smith $100) Replay attack • Memorize a message and send it multiple times 21 You');
INSERT INTO course_chunks (class_id, source, topic_tag, content) VALUES (1, 'lecture', 'Web Security', 'Data collected about you can be searched with a warrant • Google knows everywhere you’ve been, so law enforcement does too (geofence warrant) • Lists of people who searched for topics • E-mails and chat messages • Google Transparency Report • 192,408 requests made to Google July-December 2022 16 End-to-end encryption • Some chat apps promise that the chat provider can’t read your messages • Technical details for WhatsApp: “WhatsApp Encryption Overview” paper • How do you know the app isn’t lying to you about the encryption status? 17 Agenda • Review • Network attacks • Eavesdropping • Replay • Masquerading • Man-in-the-middle • Web attacks 18 Replay attack • Memorize a message and send it multiple times 19 Replay attack • Memorize a message and send it multiple times 20 You myBank Evil Encrypt(Pay Smith $100) Replay attack • Memorize a message and send it multiple times 21 You myBank Evil Encrypt(Pay Smith $100) Replay attack defenses • Add something unique in each message: • Timestamp • Sequence number • Server will ignore messages with same ID 22 Replay attack defenses • Add something unique in each message (ID): • Timestamp • Sequence number • Server will ignore messages with same ID 23 You myBank Evil Encrypt(#23 Pay Smith $100) Agenda • Review • Network attacks • Eavesdropping • Replay • Masquerading • Man-in-the-middle • Web attacks 24 Masquerading • Pretend to be a website • Copy the HTML and host the copy 25 Masquerading defense • Verify validity of public key using the certificate. 26 Man-in-the-middle attack 27 • Intercept and potentially manipulate the communication between two parties • The attacker intercepts the server''s public key and replaces it with their own "evil" public key before it reaches the client. Man-in-the-middle defense • Verify validity of public key using the certificate 28 Agenda • Encryption review • Network attacks • Web attacks • SQL injection • Cross-site scripting • Cross-site request forgery (CSRF) • Sybil • De-anonymization 29 Network attacks vs. web attacks • Network attacks (messages): target data in transit between client and server • Web attacks (servers): target the server-side application (e.g., our Flask app) 30 SQL injection attack 31 Smith1 123 User Password Client – Login Screen Server Database Server will run: SELECT hash FROM passwords WHERE user=‘Smith1’ • You think you''re getting data, but you''re really getting code SQL Injection • What about user name: ''; DROP TABLE passwords • Semicolon ( ; ) is used to separate sql commands. 32 ''; DROP TABLE passwords 123 User Password Client – Login Screen Server Database Server will run: SELECT hash FROM passwords WHERE user=‘ ’; DROP TABLE passwords SQL injection attack 33 SQL injection defense • Use prepared statement (?) • Python/Flask bad example cur = connection.execute( "SELECT * FROM users " "WHERE username = “ + username) • Python/Flask good example cur = connection.execute( "SELECT * FROM users " "WHERE username = ?", (username,)) 34 Agenda • Encryption review • Network attacks • Web');
INSERT INTO course_chunks (class_id, source, topic_tag, content) VALUES (1, 'lecture', 'Web Security', '(servers): target the server-side application (e.g., our Flask app) 30 SQL injection attack 31 Smith1 123 User Password Client – Login Screen Server Database Server will run: SELECT hash FROM passwords WHERE user=‘Smith1’ • You think you''re getting data, but you''re really getting code SQL Injection • What about user name: ''; DROP TABLE passwords • Semicolon ( ; ) is used to separate sql commands. 32 ''; DROP TABLE passwords 123 User Password Client – Login Screen Server Database Server will run: SELECT hash FROM passwords WHERE user=‘ ’; DROP TABLE passwords SQL injection attack 33 SQL injection defense • Use prepared statement (?) • Python/Flask bad example cur = connection.execute( "SELECT * FROM users " "WHERE username = “ + username) • Python/Flask good example cur = connection.execute( "SELECT * FROM users " "WHERE username = ?", (username,)) 34 Agenda • Encryption review • Network attacks • Web attacks • SQL injection • Cross-site scripting • Sybil • De-anonymization 35 Cross-site scripting attack • If you allow users to post comments or other text, they can put HTML tags • <script> tag loads code that runs in other users'' browsers • Example: Nice picture! <script src=" /> 36 Cross-site scripting defense • Escape all user input before being used. • Use HTML escapes <script> => &lt;script&gt; 37 Agenda • Encryption review • Network attacks • Web attacks • SQL injection • Cross-site scripting • Cross-site request forgery (CSRF) • Sybil • De-anonymization 38 Cross-site request forgery (CSRF) • Cross-site request forgery (CSRF) • Pronounced "see surf" • Trick a user into submitting a request they didn''t intend • Browser handles request and includes cookies 39 Visualization: CSRF attack • I have an account on Insta485 and I''m logged in • Get a phishing email like this <form> <input type="hidden" value="You''ve been attacked!"> ... 40 Visualization: CSRF attack • Click the link • Brower includes insta485 cookies • Malicious post 41 Visualization: CSRF defense • Synchronizer Token Pattern: • HTML form includes a unique token per request <form> <input type="hidden" name="csrf_token" value="IjU5ZjNlMjhj..."> ... • Check token on form submission • Usually done by server-side dynamic pages library • Example: Flask-WTF 42 *SameSite=Strict has limitations Agenda • Encryption review • Network attacks • Web attacks • SQL injection • Cross-site scripting • Cross-site request forgery (CSRF) • Sybil • De-anonymization 43 Sybil attack • One real-life user pretends to be multiple online users • Vote more than once • Fake reviews • Fake followers. 44 Image: creepypasta.wikia.com Sybil attack defenses • Require phone numbers. • CAPTCHAs 45 Agenda • Encryption review • Network attacks • Web attacks • SQL injection • Cross-site scripting • Sybil • De-anonymization 46 De-anonymization attack • De-anonymization attack: recover identifiers from de-identified data 47 Historical data leaks • Washington state school records • University of Washington hospital: ~1M patients • Credit information on basically everyone in the US 48 Data that''s stored about you • Google • All your e-mails and chat messages • Your');
INSERT INTO course_chunks (class_id, source, topic_tag, content) VALUES (1, 'lecture', 'Web Security', '• Usually done by server-side dynamic pages library • Example: Flask-WTF 42 *SameSite=Strict has limitations Agenda • Encryption review • Network attacks • Web attacks • SQL injection • Cross-site scripting • Cross-site request forgery (CSRF) • Sybil • De-anonymization 43 Sybil attack • One real-life user pretends to be multiple online users • Vote more than once • Fake reviews • Fake followers. 44 Image: creepypasta.wikia.com Sybil attack defenses • Require phone numbers. • CAPTCHAs 45 Agenda • Encryption review • Network attacks • Web attacks • SQL injection • Cross-site scripting • Sybil • De-anonymization 46 De-anonymization attack • De-anonymization attack: recover identifiers from de-identified data 47 Historical data leaks • Washington state school records • University of Washington hospital: ~1M patients • Credit information on basically everyone in the US 48 Data that''s stored about you • Google • All your e-mails and chat messages • Your location history (where your phone has been, computers you''ve logged into) • All your web searches • Backups onto Google Drive • University of Michigan • (You can ask for almost all of this yourself!) • Grades • Notes from meetings with advisors • Admissions decisions • Who''s been referred to the Honor Council 49 Massachusetts data release • In mid-90s, MA government insurance company (“GIC”) released data on state employee hospital visits • Data was anonymized • Massachusetts health records • Drop name, address, SSN • Keep <zip, birthday, gender, health details> • MIT Student Latanya Sweeney combined anonymized data with Cambridge, MA voter rolls • GIC data: zip, gender, DOB • Voter rolls: name, zip, gender, DOB • Male; 02138; July 31, 1945 50 Massachusetts data release • After joining hospital data with voter data, governor''s records could be deidentified! • Only six people in Cambridge shared his birth date • Only three of them men, and of them • Only he lived in his ZIP code • Sweeney sent the Governor’s health records to his office • Included diagnoses and prescriptions! 51 Massachusetts data release • 87% of Americans uniquely identified by zip, gender, DOB • What can we do? 52 Database privacy • Unsolvable problem • Any release of data improves adversary''s ability to identify • Only sure way is to release nothing 53 Summary: Network attacks • Eavesdropping: Listen to network traffic going through a router • Masquerading: Fake version of a real website like a bank • Man-in-the-middle: Encrypted communication ... but with the attacker''s public key • Replay: Save a (possibly encrypted) message and send it again later 54 Summary: Web attacks • SQL injection: You think you''re getting data, but you''re really getting code • Cross-site scripting (XSS) injects code into another page • Cross-site request forgery (CSRF) tricks a user into submitting a request they didn''t intend • Sybil attack fakes reviews or search results • De-anonymization recovers identifiers from anonymized data 55');
INSERT INTO course_chunks (class_id, source, topic_tag, content) VALUES (1, 'lecture', 'Web Security', 'can we do? 52 Database privacy • Unsolvable problem • Any release of data improves adversary''s ability to identify • Only sure way is to release nothing 53 Summary: Network attacks • Eavesdropping: Listen to network traffic going through a router • Masquerading: Fake version of a real website like a bank • Man-in-the-middle: Encrypted communication ... but with the attacker''s public key • Replay: Save a (possibly encrypted) message and send it again later 54 Summary: Web attacks • SQL injection: You think you''re getting data, but you''re really getting code • Cross-site scripting (XSS) injects code into another page • Cross-site request forgery (CSRF) tricks a user into submitting a request they didn''t intend • Sybil attack fakes reviews or search results • De-anonymization recovers identifiers from anonymized data 55');
INSERT INTO course_chunks (class_id, source, topic_tag, content) VALUES (1, 'lecture', 'REST APIs', 'REST APIs Slides by Raed Almomani & Andrew DeOrio Agenda • REST API intro • JSON • Collections and pagination • REST API Verbs and Status codes. • Safety and idempotence 2 REST API • REST • "Representational State Transfer" • API • "Application Programming Interface" • How Client/Server share data. Not a REST API 4 REST API 5 REST API • JavaScript runs in browser • JavaScript receives JSON data from server • JavaScript renders data on page 6 REST APIs use HTTP • HTTP request includes a Method • HTTP response includes a Status code and JSON data ➢GET /api/v1/p/1/ HTTP/1.0 < HTTP/1.0 200 OK < Content-Type: application/json { "age": "2019-09-20 17:28:59", "img_url": "/uploads/122a7d27ca1d7420a1072f695d9290fad4501a41.jpg", "owner": "awdeorio", "owner_img_url": "/uploads/e1a7c5c32973862ee15173b0259e3efdb6a391af.jpg", ... } 7 Agenda • REST API intro • JSON • Collections and pagination • REST API Verbs and Status codes. • Safety and idempotence 8 JSON • JSON: JavaScript Object Notation. • Lightweight data-interchange format • Based on JavaScript syntax • Commonly used to send data from a server to a web client 9 JSON structures • Object: a collection of name/value pairs { "name": "DeOrio", "num_chickens": 4 } • Array: an ordered list of values [ "Marilyn", "Maude", "Myrtle II", "Mabel"] • A value is: • string • number • true • false • null • Object • Array 10 Valid JSON • Pitfall: no trailing commas allowed! { "login":"awdeorio", "id":7503005, ... "updated_at": "2017-12-12T19:11:17Z” /, } • More details: 11 Example JSON for Insta485 image post 12 Agenda • REST API intro • JSON • Collections and pagination • REST API Verbs and Status codes. • Safety and idempotence 13 Detail view AKA item view • Our previous example showed a REST API detail view or item view • It returns one object from the database • Notice the post id part of the URL • Also called a "slug" $ GET /api/v1/posts/1/ HTTP/1.0 { "age": "2019-09-20 17:28:59", "img_url": "/uploads/122a7d27ca1d7420a1072f695d9290fad4501a41.jpg", "owner": "awdeorio", "owner_img_url": "/uploads/e1a7c5c32973862ee15173b0259e3efdb6a391af.jpg", ... "url": "/api/v1/posts/1/" } 14 List view AKA collection view • REST APIs often expose collections of items $ GET /api/v1/posts/ HTTP/1.0 { "results": [ { "postid": 3, "url": "/api/v1/posts/3/" ... }, { "postid": 2, "url": "/api/v1/posts/2/" ... }, ... ] } 15 Pagination • Pagination from the UI perspective • REST API enables this • Instagram et. al use REST API pagination for infinite scroll 16 ... Pagination • List views should return a limited number of items • What if there were 10 million posts? • Sensible default, e.g., 10 posts • $ GET /api/v1/posts/ HTTP/1.0 • Get the next 10 results • $ GET /api/v1/posts/?page=2 HTTP/1.0 • Customizable size • $ GET /api/v1/posts/?size=20 HTTP/1.0 17 Agenda • REST API intro • JSON • Collections and pagination • REST API Verbs and Status codes. • Safety and idempotence 18 REST API verbs and status codes • All our examples so far have been GET requests • GET request • 200 OK response • This takes care of reading data. What about create,');
INSERT INTO course_chunks (class_id, source, topic_tag, content) VALUES (1, 'lecture', 'REST APIs', '[ { "postid": 3, "url": "/api/v1/posts/3/" ... }, { "postid": 2, "url": "/api/v1/posts/2/" ... }, ... ] } 15 Pagination • Pagination from the UI perspective • REST API enables this • Instagram et. al use REST API pagination for infinite scroll 16 ... Pagination • List views should return a limited number of items • What if there were 10 million posts? • Sensible default, e.g., 10 posts • $ GET /api/v1/posts/ HTTP/1.0 • Get the next 10 results • $ GET /api/v1/posts/?page=2 HTTP/1.0 • Customizable size • $ GET /api/v1/posts/?size=20 HTTP/1.0 17 Agenda • REST API intro • JSON • Collections and pagination • REST API Verbs and Status codes. • Safety and idempotence 18 REST API verbs and status codes • All our examples so far have been GET requests • GET request • 200 OK response • This takes care of reading data. What about create, modify and delete? 19 REST API HTTP verbs • GET: return a post • POST: create a new post • PATCH: modify part of an existing post • PUT: replace the entire existing post • DELETE: delete a post 20 POST request •POST creates an object • Request includes JSON body POST /api/v1/posts/ HTTP/1.0 { "img_url": "122a7d27ca1d7420a1072f695d9290fad4501a41.jpg", "owner": "awdeorio", ... } 21 POST response •POST returns 201 CREATED on success • Response includes a copy of the created object • Object usually includes a link to itself POST /api/v1/p/ HTTP/1.0 ... HTTP/1.0 201 CREATED { "img_url": "122a7d27ca1d7420a1072f695d9290fad4501a41.jpg", "owner": "awdeorio", ... "url": "/api/v1/p/1/" } 22 PATCH request •PATCH modifies part of an existing object • Request URL includes an ID • Request includes JSON body • Example: change the picture in a post • Notice that the JSON body is short, and only contains the field that should be modified PATCH /api/v1/p/1/ HTTP/1.0 { "img_url": "ad7790405c539894d25ab8dcf0b79eed3341e109.jpg", } 23 PATCH response •PATCH returns 200 OK on success • Response includes a copy of the entire modified object PATCH /api/v1/p/1/ HTTP/1.0 ... HTTP/1.0 200 OK { "img_url": "ad7790405c539894d25ab8dcf0b79eed3341e109.jpg", "owner": "awdeorio", ... "url": "/api/v1/p/1/" } 24 PUT request • PUT replaces an entire existing object • Request URL includes an ID • Request includes JSON body • Example: replace an entire post • The JSON body is long, and contains a replacement value for every field PUT /api/v1/p/1/ HTTP/1.0 { "img_url": ..., "owner": "jflinn", "owner_img_url": ..., ... } 25 PUT response •PUT returns 200 OK on success • Response includes a copy of the entire modified object PUT /api/v1/p/1/ HTTP/1.0 ... HTTP/1.0 200 OK { "img_url": ..., "owner": "jflinn", "owner_img_url": ..., ... } 26 DELETE request •DELETE removes an object • Request URL includes an ID • No body in request DELETE /api/v1/p/1/ HTTP/1.0 27 DELETE response on success •DELETE returns 204 NO CONTENT on success • No body in response DELETE /api/v1/p/1/ HTTP/1.0 ... HTTP/1.0 204 NO CONTENT 28 DELETE response on failure •GET a deleted item, receive a 404 response DELETE /api/v1/p/1/ HTTP/1.0 HTTP/1.0 204 NO CONTENT GET /api/v1/p/1/ HTTP/1.0 HTTP/1.0 404');
INSERT INTO course_chunks (class_id, source, topic_tag, content) VALUES (1, 'lecture', 'REST APIs', 'object • Request URL includes an ID • Request includes JSON body • Example: replace an entire post • The JSON body is long, and contains a replacement value for every field PUT /api/v1/p/1/ HTTP/1.0 { "img_url": ..., "owner": "jflinn", "owner_img_url": ..., ... } 25 PUT response •PUT returns 200 OK on success • Response includes a copy of the entire modified object PUT /api/v1/p/1/ HTTP/1.0 ... HTTP/1.0 200 OK { "img_url": ..., "owner": "jflinn", "owner_img_url": ..., ... } 26 DELETE request •DELETE removes an object • Request URL includes an ID • No body in request DELETE /api/v1/p/1/ HTTP/1.0 27 DELETE response on success •DELETE returns 204 NO CONTENT on success • No body in response DELETE /api/v1/p/1/ HTTP/1.0 ... HTTP/1.0 204 NO CONTENT 28 DELETE response on failure •GET a deleted item, receive a 404 response DELETE /api/v1/p/1/ HTTP/1.0 HTTP/1.0 204 NO CONTENT GET /api/v1/p/1/ HTTP/1.0 HTTP/1.0 404 NOT FOUND 29 REST API status codes • 200 OK • 201 Created • Successful creation after POST • 204 No Content • Successful DELETE • 304 Not Modified • Used for conditional GET calls to reduce bandwidth usage • 400 Bad Request • General error • 401 Unauthorized • Missing or invalid authentication • 403 Forbidden • User is not authorized • 404 Not Found • Resource could not be found • 409 Conflict • E.g., duplicate entries and deleting root objects when cascade-delete is not supported • 500 Internal Server Error • General catch-all for server-side exceptions 30 Agenda • REST API intro • JSON • Collections and pagination • REST API Verbs and Status codes. • Safety and idempotence 31 Safety and Idempotency • Safe • Read-only request • Well-designed GET request • No change to state on server (the data on the server remains the same before and after the request) • Idempotent • Sending the request multiple times leads to the same result on the server as sending it once • "If I ask this twice, will the same thing have happened as if I asked it once?" • Example: Deleting a file 32 Motivation for idempotency • The Internet is a messy place – lots of network failures, network handovers, other people making requests • When something is idempotent, we can retry the request 33 Motivation example • You’re on campus connected to Mwireless • You click “like” on a post as you walk out the door • App sends a request to the server to update the like count • Phone loses MWireless connection before response arrives • Q: What should the app do when it connects to the cellular network? • A: If the request method is idempotent the app can send it again 34 Partner Q: idempotence in the real world • Which of these human requests are safe? Which are idempotent? • "What is your name?" • "Turn the book to page 56." • "What time is it?" • "I would like a bowl with fried rice and orange chicken”');
INSERT INTO course_chunks (class_id, source, topic_tag, content) VALUES (1, 'lecture', 'REST APIs', 'for idempotency • The Internet is a messy place – lots of network failures, network handovers, other people making requests • When something is idempotent, we can retry the request 33 Motivation example • You’re on campus connected to Mwireless • You click “like” on a post as you walk out the door • App sends a request to the server to update the like count • Phone loses MWireless connection before response arrives • Q: What should the app do when it connects to the cellular network? • A: If the request method is idempotent the app can send it again 34 Partner Q: idempotence in the real world • Which of these human requests are safe? Which are idempotent? • "What is your name?" • "Turn the book to page 56." • "What time is it?" • "I would like a bowl with fried rice and orange chicken” • "Turn left“ • "Turn East" 35 Partner Q: idempotence in HTTP • Which of these HTTP verbs are safe? • GET • POST • PUT • DELETE • HEAD • Which of them are idempotent? 37 GET , HEAD • Safe • Doesn''t change state on server • Idempotent • Safe implies idempotent because no state is changing • GET and HEAD are read-only 38 PUT, POST • PUT • Not safe: changes server state by modifying an object • Idempotent: a second duplicate PUT request won''t have different effect than sending one • POST • Not safe: changes server state by creating a new object • Not idempotent: two POST requests create two new objects 39 DELETE, PATCH • DELETE • Not safe: changes state • Idempotent: A second DELETE means the object is still gone • PATCH • It''s complicated • With what HTTP spec says, we can''t assume it''s safe or that it''s idempotent 40 Idempotent details • Multiple identical requests should have the same effect on the server as a single request • The same request can be made twice with no negative consequences on the server • Does not mean that the same request always returns the same response • Does mean that a request has NO side effects • Why does Idempotency matter? If a request fails, can we automatically try again, but only if it is idempotent. • Reference: HTTP RFC 4.2.2 41 Summary • A client and a server can communicate via a REST API • Two servers can communicate via a REST API • REST APIs use HTTP • REST APIs are machine-readable • REST APIs usually return JSON data • Idempotent methods can be repeated automatically 42 Public APIs • GitHub • LinkedIn • Facebook • Twitter 43');
INSERT INTO course_chunks (class_id, source, topic_tag, content) VALUES (1, 'lecture', 'REST APIs', 'always returns the same response • Does mean that a request has NO side effects • Why does Idempotency matter? If a request fails, can we automatically try again, but only if it is idempotent. • Reference: HTTP RFC 4.2.2 41 Summary • A client and a server can communicate via a REST API • Two servers can communicate via a REST API • REST APIs use HTTP • REST APIs are machine-readable • REST APIs usually return JSON data • Idempotent methods can be repeated automatically 42 Public APIs • GitHub • LinkedIn • Facebook • Twitter 43');
INSERT INTO course_chunks (class_id, source, topic_tag, content) VALUES (1, 'lecture', 'Clientside Dynamic Pages', 'Client-side Dynamic Pages Agenda • Review • Client-side dynamic pages • JavaScript • Event-driven programming • Summary 2 Review: Document Object Model (DOM) • The DOM is a data structure built from the HTML • HTML tags form a tree <html> <head></head> <body> <p>Hello world!</p> <p>I &lt;3 chickens</p> </body> </html> 3 html body P P Hello World! I < 3 Head Review: server-side dynamic pages • Server-side dynamic pages: Response is the output of a function. • Client makes a request • Server executes a function • Output is usually HTML • Server response is the output of the function 4 Server-side dynamic pages require reload • With server-side dynamic pages, if one part of the page updates, the entire page must reload • Example: Project 2 like button 5 Server-side dynamic pages limitations • More limitations of server-side dynamic pages • No in-browser chat • No browser-based field validation • E.g., password strength, valid email address format • No grabbable maps • No deferred data loading in Gmail • Add/delete comment without a page reload • Like/unlike without a page reload • Double click to like • Infinite scroll 6 Agenda • Review • Client-side dynamic pages • JavaScript • Event-driven programming 7 Client-side dynamic pages • Problem: Server code can''t change the page after it has been generated and transferred to the client’s browser • Solution: Client-side dynamic pages - Code running in the client’s browser modifies the DOM. The rendered page changes. 8 Client-side dynamic pages no reload • With client-side dynamic pages, you can update just one part of the page • Example: Project 3 like button 9 Client-side dynamic pages use JavaScript • We need a programming language in the client’s web browser • We need functions to manipulate the DOM “JavaScript has sharp edges, but we’re going to use it safely. ” 10 Agenda • Review • Client-side dynamic pages • JavaScript • Event-driven programming 11 document API • The document API represents the web page • Document Object Model (DOM) • The document API modifies the DOM • When the DOM changes, the rendered page changes 12 <html> <body> <script> document.write("Hello, World!"); </script> </body> </html> console API •console API writes text to the developer console 13 <html> <body> <script> console.log("Hello, World!"); </script> </body> </html> What is JavaScript? • "Python with C++ syntax" • With more design flaws • Only programming language that web browsers support • Has nothing to do with Java 14 Why JavaScript? • It''s the only programming language browsers understand • Specialty is event-driven and asynchronous applications 15 JavaScript reputation • Syntax pitfalls • == vs. === • x=5; (global) vs. let x=5; (local) • var vs. let and const • Funny-looking loops const chickens = [''Magda'', ''Marilyn'', ''Myrtle II'']; chickens.forEach((chicken) => { console.log(chicken); }); • Confusion about event-driven and asynchronous programming • Covered in lecture 16 Example: like button • Use the document API to change the DOM 17 <html><body> <span id="numLikes">0</span> likes <button id="likeBtn">like</button> </body></html> Example: like button');
INSERT INTO course_chunks (class_id, source, topic_tag, content) VALUES (1, 'lecture', 'Clientside Dynamic Pages', 'rendered page changes 12 <html> <body> <script> document.write("Hello, World!"); </script> </body> </html> console API •console API writes text to the developer console 13 <html> <body> <script> console.log("Hello, World!"); </script> </body> </html> What is JavaScript? • "Python with C++ syntax" • With more design flaws • Only programming language that web browsers support • Has nothing to do with Java 14 Why JavaScript? • It''s the only programming language browsers understand • Specialty is event-driven and asynchronous applications 15 JavaScript reputation • Syntax pitfalls • == vs. === • x=5; (global) vs. let x=5; (local) • var vs. let and const • Funny-looking loops const chickens = [''Magda'', ''Marilyn'', ''Myrtle II'']; chickens.forEach((chicken) => { console.log(chicken); }); • Confusion about event-driven and asynchronous programming • Covered in lecture 16 Example: like button • Use the document API to change the DOM 17 <html><body> <span id="numLikes">0</span> likes <button id="likeBtn">like</button> </body></html> Example: like button • Use the document API to change the DOM 18 <html><body> <span id="numLikes">0</span> likes <button id="likeBtn">like</button> <script> let numLikes = 0; // HACK global function addLike() { numLikes += 1; const n = document.getElementById(''numLikes''); n.textContent = numLikes; } addLike(); </script> </body></html> JS changes DOM -> rendered page changes • JavaScript programs change the DOM • When the DOM changes, the rendered page changes • No page reload • No server interaction required • All this happens in the client’ s browser • This is client-side dynamic pages 19 Agenda • Review • Client-side dynamic pages • JavaScript • Event-driven programming 20 Event-driven programming • Problem: How to run addLike() on button press? • More generally, how to respond to user input? • Solution: Event-driven programming • In event-driven programming, the flow of the program is determined by external events like user input. • Built-in support from the JavaScript interpreter and the browser 21 Not event-driven programming • Our previous version specified everything the program did • It did not respond to user input • Next, we will let the user determine what the program does 22 <html><body> <span id="numLikes">0</span> likes <button id="likeBtn">like</button> <script> let numLikes = 0; // HACK global function addLike() { numLikes += 1; const n = document.getElementById(''numLikes''); n.textContent = numLikes; } addLike(); </script> </body></html> Events • An event is an action from outside handled by the program • Events often come from outside the program • User clicks a button • User scrolls to the end of the page • Network response arrives • Full list of events 23 Events • A button click is an event • JavaScript click 24 <html><body> <span id="numLikes">0</span> likes <button id="likeBtn">like</button> <script> let numLikes = 0; // HACK global function addLike() { numLikes += 1; const n = document.getElementById(''numLikes''); n.textContent = numLikes; } const btn = document.getElementById(''likeBtn''); btn.addEventListener("click", addLike); </script> </body></html> Event handler • An event handler is a function • An event handler runs after an event occurs • AKA callback 25 <html><body> <span id="numLikes">0</span> likes <button id="likeBtn">like</button> <script> let numLikes = 0; // HACK global function addLike() { numLikes');
INSERT INTO course_chunks (class_id, source, topic_tag, content) VALUES (1, 'lecture', 'Clientside Dynamic Pages', 'function addLike() { numLikes += 1; const n = document.getElementById(''numLikes''); n.textContent = numLikes; } addLike(); </script> </body></html> Events • An event is an action from outside handled by the program • Events often come from outside the program • User clicks a button • User scrolls to the end of the page • Network response arrives • Full list of events 23 Events • A button click is an event • JavaScript click 24 <html><body> <span id="numLikes">0</span> likes <button id="likeBtn">like</button> <script> let numLikes = 0; // HACK global function addLike() { numLikes += 1; const n = document.getElementById(''numLikes''); n.textContent = numLikes; } const btn = document.getElementById(''likeBtn''); btn.addEventListener("click", addLike); </script> </body></html> Event handler • An event handler is a function • An event handler runs after an event occurs • AKA callback 25 <html><body> <span id="numLikes">0</span> likes <button id="likeBtn">like</button> <script> let numLikes = 0; // HACK global function addLike() { numLikes += 1; const n = document.getElementById(numLikes''); n.textContent = numLikes; } const btn = document.getElementById("likeBtn"); btn.addEventListener("click", addLike); </script> </body></html> Event table • The event table maps events to event handlers • Nomenclature is not universal •addEventListener() updates the event table 26 <html><body> <span id="numLikes">0</span> likes <button id="likeBtn">like</button> <script> let numLikes = 0; // HACK global function addLike() { numLikes += 1; const n = document.getElementById(''numLikes''); n.textContent = numLikes; } const btn = document.getElementById(''likeBtn''); btn.addEventListener(''click'', addLike); </script> </body></html> Event Table likeBtn click addLike Event queue • Problem: The interpreter is busy when an event occurs • Solution: Add event handlers to the event queue • The event queue stores event handlers waiting to execute 27 Event Queue addLike head Stack • Problem: Event handlers need to be executed • Solution: Stack • The stack executes functions • Same as 100-level programming • When the stack is empty, an event handler is removed from the event queue and executed 28 Event loop • Problem: How to check for events, enqueue, and execute them? • Solution: The event loop • The event loop • Checks for events • Adds event handlers to the event queue • Executes a function from the event queue • The event loop is built into the interpreter 29 while (True) { handler = check_event_table(); event_queue.push(handler); if (!event_queue.empty()) { fxn = event_queue.pop(); fxn(); // execute } } One button click 30 <html><body> <span id="numLikes">0</span> likes <button id="likeBtn">like</button> <script> let numLikes = 0; function addLike() { numLikes += 1; const n = document.getElementById(''numLikes''); n.textContent = numLikes; } const btn = document.getElementById(''likeBtn''); btn.addEventListener(''click'', addLike); </script> </body></html> Event Queue headEvent Table likeBtn click addLike DOM Rendered Page html body span id=... button id=... script "0" Stack let ..."likes" One button click 31 <html><body> <span id="numLikes">0</span> likes <button id="likeBtn">like</button> <script> let numLikes = 0; function addLike() { numLikes += 1; const n = document.getElementById(numLikes''); n.textContent = numLikes; } const btn = document.getElementById("likeBtn"); btn.addEventListener("click", addLike); </script> </body></html> Event Queue addLike() headEvent Table likeBtn click addLike DOM Rendered Page html body span id=... button id=... script "0" Stack let ..."likes" Two fast clicks 32 <html><body> <span');
INSERT INTO course_chunks (class_id, source, topic_tag, content) VALUES (1, 'lecture', 'Clientside Dynamic Pages', 'The event loop is built into the interpreter 29 while (True) { handler = check_event_table(); event_queue.push(handler); if (!event_queue.empty()) { fxn = event_queue.pop(); fxn(); // execute } } One button click 30 <html><body> <span id="numLikes">0</span> likes <button id="likeBtn">like</button> <script> let numLikes = 0; function addLike() { numLikes += 1; const n = document.getElementById(''numLikes''); n.textContent = numLikes; } const btn = document.getElementById(''likeBtn''); btn.addEventListener(''click'', addLike); </script> </body></html> Event Queue headEvent Table likeBtn click addLike DOM Rendered Page html body span id=... button id=... script "0" Stack let ..."likes" One button click 31 <html><body> <span id="numLikes">0</span> likes <button id="likeBtn">like</button> <script> let numLikes = 0; function addLike() { numLikes += 1; const n = document.getElementById(numLikes''); n.textContent = numLikes; } const btn = document.getElementById("likeBtn"); btn.addEventListener("click", addLike); </script> </body></html> Event Queue addLike() headEvent Table likeBtn click addLike DOM Rendered Page html body span id=... button id=... script "0" Stack let ..."likes" Two fast clicks 32 <html><body> <span id="numLikes">0</span> likes <button id="likeBtn">like</button> <script> let numLikes = 0; function addLike() { numLikes += 1; const n = document.getElementById(''numLikes''); n.textContent = numLikes; } const btn = document.getElementById(''likeBtn''); btn.addEventListener(''click'', addLike); </script> </body></html> Event Queue headEvent Table likeBtn click addLike DOM Rendered Page html body span id=... button id=... script "0" Stack let ..."likes" x2 JavaScript is single-threaded • JavaScript is single-threaded • It can only do one thing at a time 33 Long-running function • What happens to our example if there’s a long-running function? 34 <html><body> <span id="numLikes">0</span> likes <button id="likeBtn">like</button> <script> let numLikes = 0; function addLike() { numLikes += 1; const n = document.getElementById(numLikes''); n.textContent = numLikes; } const btn = document.getElementById("likeBtn"); btn.addEventListener("click", addLike); long_running_function(); </script> </body></html> Long-running function • What happens to our example if there’s a long-running function? • Everything else must wait • The like button doesn’t work while the function runs 35 <html><body> <span id="numLikes">0</span> likes <button id="likeBtn">like</button> <script> let numLikes = 0; function addLike() { numLikes += 1; const n = document.getElementById(''numLikes''); n.textContent = numLikes; } const btn = document.getElementById(''likeBtn''); btn.addEventListener(''click'', addLike); long_running_function(); </script> </body></html> Multiple events • What happens to our example if there are two events? 36 <html> <body> <span id="numLikes">0</span> likes <button id="likeBtn">like</button> <script> let numLikes = 0; // HACK global function addLike() { numLikes += 1; const n = document.getElementById(''numLikes''); n.textContent = numLikes; } function subLike() { numLikes -= 1; const n = document.getElementById(''numLikes''); n.textContent = numLikes; } const btn = document.getElementById(''likeBtn"; btn.addEventListener(''mouseenter'',addLike); btn.addEventListener(''mouseleave'', subLike); </script> </body> </html> Multiple events • What happens to our example if there are two events? • Two entries in the event table 37 <html> <body> <span id="numLikes">0</span> likes <button id="likeBtn">like</button> <script> let numLikes = 0; // HACK global function addLike() { numLikes += 1; const n = document.getElementById(''numLikes''); n.textContent = numLikes; } function subLike() { numLikes -= 1; const n = document.getElementById(''numLikes''); n.textContent = numLikes; } const btn = document.getElementById("likeBtn"); btn.addEventListener("mouseenter", addLike); btn.addEventListener("mouseleave", subLike); </script> </body> </html> Event Table likeBtn mouseenter addLike likeBtn mouseleave subLike Summary • Client-side dynamic pages: Code running in the client’ s web browser modifies the DOM. The rendered');
INSERT INTO course_chunks (class_id, source, topic_tag, content) VALUES (1, 'lecture', 'Clientside Dynamic Pages', 'likes <button id="likeBtn">like</button> <script> let numLikes = 0; // HACK global function addLike() { numLikes += 1; const n = document.getElementById(''numLikes''); n.textContent = numLikes; } function subLike() { numLikes -= 1; const n = document.getElementById(''numLikes''); n.textContent = numLikes; } const btn = document.getElementById(''likeBtn"; btn.addEventListener(''mouseenter'',addLike); btn.addEventListener(''mouseleave'', subLike); </script> </body> </html> Multiple events • What happens to our example if there are two events? • Two entries in the event table 37 <html> <body> <span id="numLikes">0</span> likes <button id="likeBtn">like</button> <script> let numLikes = 0; // HACK global function addLike() { numLikes += 1; const n = document.getElementById(''numLikes''); n.textContent = numLikes; } function subLike() { numLikes -= 1; const n = document.getElementById(''numLikes''); n.textContent = numLikes; } const btn = document.getElementById("likeBtn"); btn.addEventListener("mouseenter", addLike); btn.addEventListener("mouseleave", subLike); </script> </body> </html> Event Table likeBtn mouseenter addLike likeBtn mouseleave subLike Summary • Client-side dynamic pages: Code running in the client’ s web browser modifies the DOM. The rendered page changes. • In event-driven programming, the flow of the program is determined by external events like user input. • The event loop checks for events and dispatches event handlers to the event queue • When the stack is empty, an event handler is removed from the event queue and executed 38');
INSERT INTO course_chunks (class_id, source, topic_tag, content) VALUES (1, 'lecture', 'Clientside Applications', 'Client-side applications Agenda • Review • Client/server synchronization (read) • Fetch API • Promises • Anonymous functions • Client/server synchronization (write) 2 Review: REST APIs are for data exchange • JavaScript runs in browser • JavaScript receives JSON data from server • JavaScript renders data on page 3 Review: Client-side dynamic pages • Problem: Server code can''t change the page after it has been generated and transferred to the client’s browser • Solution: Client-side dynamic pages - Code running in the client’s web browser modifies the DOM. The rendered page changes. 4 Review: Client-side dynamic pages no reload • With client-side dynamic pages, you can update just one part of the page • Example: Project 3 like button 5 Last time • Recall our like button • addLike() runs when user clicks like button • Event-driven programming 6 <html><body> <span id="numLikes">0</span> likes <button id="likeBtn">like</button> <script> let numLikes = 0; function addLike() { numLikes += 1; const n = document.getElementById(''numLikes''); n.textContent = numLikes; } const btn = document.getElementById("likeBtn"); btn.addEventListener("click", addLike); </script> </body></html> Review: Event handler • An event handler is a function • An event handler runs after an event occurs • AKA callback 7 <html><body> <span id="numLikes">0</span> likes <button id="likeBtn">like</button> <script> let numLikes = 0; function addLike() { numLikes += 1; const n = document.getElementById(''numLikes''); n.textContent = numLikes; } const btn = document.getElementById("likeBtn"); btn.addEventListener("click", addLike); </script> </body></html> Review: Event table • The event table maps events to event handlers • Nomenclature is not universal •addEventListener() updates the event table 8 <html><body> <span id="numLikes">0</span> likes <button id="likeBtn">like</button> <script> let numLikes = 0; function addLike() { numLikes += 1; const n = document.getElementById(''numLikes''); n.textContent = numLikes; } const btn = document.getElementById("likeBtn"); btn.addEventListener("click", addLike); </script> </body></html> Event Table likeBtn click addLike Review: One button click 9 <html><body> <span id="numLikes">0</span> likes <button id="likeBtn">like</button> <script> let numLikes = 0; function addLike() { numLikes += 1; const n = document.getElementById(''numLikes''); n.textContent = numLikes; } const btn = document.getElementById("likeBtn"); btn.addEventListener("click", addLike); </script> </body></html> Event Queue headEvent Table likeBtn click addLike html body span id=... button id=... script "0" Stack let ..."likes" DOM Rendered Page Review: One button click 10 <html><body> <span id="numLikes">0</span> likes <button id="likeBtn">like</button> <script> let numLikes = 0; function addLike() { numLikes += 1; const n = document.getElementById(''numLikes''); n.textContent = numLikes; } const btn = document.getElementById("likeBtn"); btn.addEventListener("click", addLike); </script> </body></html> Event Queue headEvent Table likeBtn click addLike html body span id=... button id=... script "0" Stack let ..."likes" DOM Rendered Page What happens when the page is reloaded? Server-side vs. client-side dynamic pages Server-side dynamic pages • Server response is the output of a function • Good for database access • Server function runs SQL query • Bad for user interaction • Refresh required Client-side dynamic pages • JavaScript running in the client’s web browser modifies the DOM • Bad for database access • JS runs on client, not server • Good for user interaction • Modify the DOM without refresh 11 Can we have the best of both worlds? Synchronize client and server •');
INSERT INTO course_chunks (class_id, source, topic_tag, content) VALUES (1, 'lecture', 'Clientside Applications', 'click 10 <html><body> <span id="numLikes">0</span> likes <button id="likeBtn">like</button> <script> let numLikes = 0; function addLike() { numLikes += 1; const n = document.getElementById(''numLikes''); n.textContent = numLikes; } const btn = document.getElementById("likeBtn"); btn.addEventListener("click", addLike); </script> </body></html> Event Queue headEvent Table likeBtn click addLike html body span id=... button id=... script "0" Stack let ..."likes" DOM Rendered Page What happens when the page is reloaded? Server-side vs. client-side dynamic pages Server-side dynamic pages • Server response is the output of a function • Good for database access • Server function runs SQL query • Bad for user interaction • Refresh required Client-side dynamic pages • JavaScript running in the client’s web browser modifies the DOM • Bad for database access • JS runs on client, not server • Good for user interaction • Modify the DOM without refresh 11 Can we have the best of both worlds? Synchronize client and server • Goal: synchronize client and server • Server keeps track of the database • Client updates the user interface • Client and server communicate via a REST API 12 Agenda • Review • Client/server synchronization (read) • Fetch API • Promises • Anonymous functions • Client/server synchronization (write) 13 Likes REST API • Problem: Client like count resets on page load • Solution: Server stores the like count, access w/ REST API 14 LIKES = 3 # HACK "Database" @app.route(''/api/v1/likes/'') def get_likes(): """Return num likes.""" context = {"numLikes": LIKES} return flask.jsonify(context), 200 $ GET /api/v1/likes/ { "numLikes": 3 } Out of sync • Number of likes is now stored in two places • Client, server • Problem: Client and server are out of sync • Solution: Client reads num likes from REST API 15 LIKES = 3 # HACK "Database" @app.route(''/api/v1/likes/'') def get_likes(): """Return num likes.""" context = {"numLikes": LIKES} return flask.jsonify(context), 200 Agenda • Review • Client/server synchronization (read) • Fetch API • Promises • Anonymous functions • Client/server synchronization (write) 16 Goal 1. "loading ..." placeholder 2. Read initial numLikes from server REST API 3. Update the page • Replace "loading ..." 17 <html><body> <span id="numLikes">loading ...</span> likes <button id="likeBtn">like</button> <script> let numLikes = 0; function addLike() { numLikes += 1; const n = document.getElementById(''numLikes''); n.textContent = numLikes; } const btn = document.getElementById("likeBtn"); btn.addEventListener("click", addLike); // Read REST API here </script> </body></html> Fetch API • Problem: How to call a REST API from a JavaScript program? • Solution: Fetch API • The Fetch API is a JavaScript function for making HTTP requests • The Fetch API is built into the browser/interpreter 18 Minimal example 1. GET request to REST API 2. When response arrives, calls handleData(data) 3. handleData() updates numLikes and updates the DOM 19 <html><body> <span id="numLikes">loading ...</span> likes <button id="likeBtn">like</button> <script> let numLikes = 0; // not shown: like button code function handleData(data) { numLikes = data.numLikes; const n = document.getElementById(''numLikes''); n.textContent = numLikes; } const dataPromise = fetchJSON("/api/v1/likes/"); dataPromise.then(handleData); </script> </body></html> Simplification •fetchJSON is a simplified version of the Fetch API • Calls built-in fetch() •');
INSERT INTO course_chunks (class_id, source, topic_tag, content) VALUES (1, 'lecture', 'Clientside Applications', 'id="likeBtn">like</button> <script> let numLikes = 0; function addLike() { numLikes += 1; const n = document.getElementById(''numLikes''); n.textContent = numLikes; } const btn = document.getElementById("likeBtn"); btn.addEventListener("click", addLike); // Read REST API here </script> </body></html> Fetch API • Problem: How to call a REST API from a JavaScript program? • Solution: Fetch API • The Fetch API is a JavaScript function for making HTTP requests • The Fetch API is built into the browser/interpreter 18 Minimal example 1. GET request to REST API 2. When response arrives, calls handleData(data) 3. handleData() updates numLikes and updates the DOM 19 <html><body> <span id="numLikes">loading ...</span> likes <button id="likeBtn">like</button> <script> let numLikes = 0; // not shown: like button code function handleData(data) { numLikes = data.numLikes; const n = document.getElementById(''numLikes''); n.textContent = numLikes; } const dataPromise = fetchJSON("/api/v1/likes/"); dataPromise.then(handleData); </script> </body></html> Simplification •fetchJSON is a simplified version of the Fetch API • Calls built-in fetch() • Calls built-in json() 20 function fetchJSON(url) { return fetch(url) .then(response => { return response.json(); }); } Client perspective and server perspective • Server sees two requests • Initial page load (index.html) • REST API request • Client has corrected initial num likes 21 GET / HTTP/1.1 200 GET /api/v1/likes/ HTTP/1.1 200 Fetch timing diagram 22 LIKES = 3 @app.route(''/api/v1/likes/'') def get_likes(): """Return num likes.""" context = {"numLikes": LIKES} return flask.jsonify(context), 200 let numLikes = 0; function handleData(data) { numLikes = data.numLikes; const n = document.getElementById(''numLikes''); n.textContent = numLikes; } const dataPromise = fetchJSON("/api/v1/likes/"); dataPromise.then(handleData); Fetch timing diagram 23 LIKES = 3 @app.route(''/api/v1/likes/'') def get_likes(): """Return num likes.""" context = {"numLikes": LIKES} return flask.jsonify(context), 200 let numLikes = 0; function handleData(data) { numLikes = data.numLikes; const n = document.getElementById(''numLikes''); n.textContent = numLikes; } const dataPromise = fetchJSON("/api/v1/likes/"); dataPromise.then(handleData); Client Server Load program … Fetch() Waiting… Getlikes() handleData() Update DOM What does fetch return? • The fetch API returns a Promise • Why not return the data? • Network requests are slow • Everything else would have to wait 24 <html><body> <span id="numLikes">loading ...</span> likes <button id="likeBtn">like</button> <script> let numLikes = 0; // not shown: like button code function handleData(data) { numLikes = data.numLikes; const n = document.getElementById(''numLikes''); n.textContent = numLikes; } const dataPromise = fetchJSON("/api/v1/likes/"); dataPromise.then(handleData); </script> </body></html> Agenda • Review • Client/server synchronization (read) • Fetch API • Promises • Anonymous functions • Client/server synchronization (write) 25 Promises • A Promise represents a value that will be available in the future •fetchJSON() sends a request •fetchJSON()returns a Promise 26 const dataPromise = fetchJSON("/api/v1/likes/"); Promise handler (callback) • Promise handler runs when Promise is completed • AKA callback • Handler is a function provided by .then() 27 function handleData(data) { numLikes = data.numLikes; const n = document.getElementById(''numLikes''); n.textContent = numLikes; } const dataPromise = fetchJSON("/api/v1/likes/"); dataPromise.then(handleData) Promise handler input • Promise handler input is the Promise''s value 28 function handleData(data) { numLikes = data.numLikes; const n = document.getElementById(''numLikes''); n.textContent = numLikes; } const dataPromise = fetchJSON("/api/v1/likes/"); dataPromise.then(handleData) Refactor question • If we refactor, will the output change? 29 function handleData(data) {');
INSERT INTO course_chunks (class_id, source, topic_tag, content) VALUES (1, 'lecture', 'Clientside Applications', '= data.numLikes; const n = document.getElementById(''numLikes''); n.textContent = numLikes; } const dataPromise = fetchJSON("/api/v1/likes/"); dataPromise.then(handleData); </script> </body></html> Agenda • Review • Client/server synchronization (read) • Fetch API • Promises • Anonymous functions • Client/server synchronization (write) 25 Promises • A Promise represents a value that will be available in the future •fetchJSON() sends a request •fetchJSON()returns a Promise 26 const dataPromise = fetchJSON("/api/v1/likes/"); Promise handler (callback) • Promise handler runs when Promise is completed • AKA callback • Handler is a function provided by .then() 27 function handleData(data) { numLikes = data.numLikes; const n = document.getElementById(''numLikes''); n.textContent = numLikes; } const dataPromise = fetchJSON("/api/v1/likes/"); dataPromise.then(handleData) Promise handler input • Promise handler input is the Promise''s value 28 function handleData(data) { numLikes = data.numLikes; const n = document.getElementById(''numLikes''); n.textContent = numLikes; } const dataPromise = fetchJSON("/api/v1/likes/"); dataPromise.then(handleData) Refactor question • If we refactor, will the output change? 29 function handleData(data) { numLikes = data.numLikes; const n = document.getElementById(''numLikes''); n.textContent = numLikes; } const dataPromise = fetchJSON("/api/v1/likes/"); dataPromise.then(handleData) function handleData(data) { numLikes = data.numLikes; const n = document.getElementById(''numLikes''); n.textContent = numLikes; } fetchJSON("/api/v1/likes/").then(handleData); Refactor solution • If we refactor, will the output change? • No. The handler runs when the response arrives. 30 function handleData(data) { numLikes = data.numLikes; const n = document.getElementById(''numLikes''); n.textContent = numLikes; } const dataPromise = fetchJSON("/api/v1/likes/"); dataPromise.then(handleData) function handleData(data) { numLikes = data.numLikes; const n = document.getElementById(''numLikes''); n.textContent = numLikes; } fetchJSON("/api/v1/likes/").then(handleData); Agenda • Review • Client/server synchronization (read) • Fetch API • Promises • Anonymous functions • Client/server synchronization (write) 31 Anonymous function motivation • This callback function is use only once 32 function handleData(data) { numLikes = data.numLikes; const n = document.getElementById(''numLikes''); n.textContent = numLikes; } fetchJSON("/api/v1/likes/").then(handleData); Anonymous functions • Refactor to use anonymous functions, or functions without a name • AKA lambda function, AKA function literal • AKA JavaScript arrow function 33 fetchJSON("/api/v1/likes/").then((data) => { numLikes = data.numLikes; const n = document.getElementById(''numLikes''); n.textContent = numLikes; }); function handleData(data) { numLikes = data.numLikes; const n = document.getElementById(''numLikes''); n.textContent = numLikes; } fetchJSON("/api/v1/likes/").then(handleData); Agenda • Review • Client/server synchronization (read) • Fetch API • Promises • Anonymous functions • Client/server synchronization (write) 34 Another synchronization problem • What happens is the user clicks the "like" button? • Problem: Client and server are out of sync again • Solution: Write to the REST API 35 REST API Write • Support PUT request in the REST API • Overwrite entire value • Return copy of value 36 LIKES = 3 # HACK "Database" @app.route(''/api/v1/likes/'', methods=["PUT"]) def put_likes(): """Set num likes and return num likes.""" global LIKES LIKES = flask.request.json["numLikes"] context = {"numLikes": LIKES} return flask.jsonify(context), 200 $ PUT localhost:8000/api/v1/likes/ numLikes=4 { "numLikes": "4" } Exercise • Where should we change our code to write to the REST API? 37 <html><body> <span id="numLikes">loading ...</span> likes <button id="likeBtn">like</button> <script> let numLikes = 0; function addLike() { numLikes += 1; const n = document.getElementById(''numLikes''); n.textContent = numLikes; } const btn = document.getElementById("likeBtn"); btn.addEventListener("click", addLike); fetchJSON("/api/v1/likes/").then((data) => { numLikes = data.numLikes; const');
INSERT INTO course_chunks (class_id, source, topic_tag, content) VALUES (1, 'lecture', 'Clientside Applications', 'Anonymous functions • Client/server synchronization (write) 34 Another synchronization problem • What happens is the user clicks the "like" button? • Problem: Client and server are out of sync again • Solution: Write to the REST API 35 REST API Write • Support PUT request in the REST API • Overwrite entire value • Return copy of value 36 LIKES = 3 # HACK "Database" @app.route(''/api/v1/likes/'', methods=["PUT"]) def put_likes(): """Set num likes and return num likes.""" global LIKES LIKES = flask.request.json["numLikes"] context = {"numLikes": LIKES} return flask.jsonify(context), 200 $ PUT localhost:8000/api/v1/likes/ numLikes=4 { "numLikes": "4" } Exercise • Where should we change our code to write to the REST API? 37 <html><body> <span id="numLikes">loading ...</span> likes <button id="likeBtn">like</button> <script> let numLikes = 0; function addLike() { numLikes += 1; const n = document.getElementById(''numLikes''); n.textContent = numLikes; } const btn = document.getElementById("likeBtn"); btn.addEventListener("click", addLike); fetchJSON("/api/v1/likes/").then((data) => { numLikes = data.numLikes; const n = document.getElementById(''numLikes''); n.textContent = numLikes; }); </script> </body></html> Solution •addLike() calls fetch with new API route 38 function addLike() { fetch("/api/v1/likes/", { method: "PUT", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ "numLikes": numLikes }), }).then((data) => { numLikes += 1; const n = document.getElementById(''numLikes''); n.textContent = numLikes; }); } Summary • Client and server synchronization is needed when they share data • E.g., the number of likes • The Fetch API is a JavaScript function for making HTTP requests • A Promise represents a value that will be available in the future • A Promise handler runs when Promise is fulfilled • Anonymous functions are functions without a name 39');
INSERT INTO course_chunks (class_id, source, topic_tag, content) VALUES (1, 'lecture', 'Asynchronous Programming', 'Asynchronous Programming Image credit: "Twisted - Network Programming Essentials" by Abe Fettig Some Slides by Andrew DeOrio Agenda • Synchronous requests • Asynchronous requests • Promise review • Asynchronous requests with ordered page updates • Closures • Idiomatic asynchronous requests with Promise chains 2 Simplified Instagram • We''ll use a simplified Instagram clone for today''s examples • No buttons • Post 1 is chickens • Post 2 is crossword 3 HTML • HTML contains an entry point for JavaScript and a function 4 <html> <body> <div id="JSEntry"></div> <script> function showPosts() { // ... } showPosts(); </script> </body> </html> Synchronous • Synchronous: one task at a time 5 function fetchJSONSync(url) { // Synchronous GET request to url, // decode JSON and return object. } function showPosts() { post1 = fetchJSONSync("/api/v1/posts/1/"); updateDOM(post1); post2 = fetchJSONSync("/api/v1/posts/2/"); updateDOM(post2); } REST API • Simplified REST API like Project 3''s post detail route $ http localhost:8000/api/v1/posts/1/ { "imgUrl": "/uploads/122a7d27ca1d7420a1072f695d9290fad4501a41.jpg", "owner": "awdeorio", } $ http localhost:8000/api/v1/posts/2/ { "imgUrl": "/uploads/ad7790405c539894d25ab8dcf0b79eed3341e109.jpg", "owner": "jflinn", } 7 JavaScript DOM manipulation • Helper function appends DOM nodes for one post 8 // Append post to DOM. function updateDOM(post) { …… } <html> <body> <div id="JSEntry"></div> <script> . . . </script> </body> </html> JavaScript DOM manipulation • Helper function appends DOM nodes for one post 10 // Append post to DOM. function updateDOM(post) { const entry = document.getElementById(''JSEntry''); const div = document.createElement(''div''); entry.appendChild(div); …… } <html> <body> <div id="JSEntry"></div> <script> . . . </script> </body> </html> JavaScript DOM manipulation • Helper function appends DOM nodes for one post 12 // Append post to DOM. function updateDOM(post) { const entry = document.getElementById(''JSEntry''); const div = document.createElement(''div''); entry.appendChild(div); const t = document.createTextNode(post.owner); div.appendChild(t); ……… } <html> <body> <div id="JSEntry"></div> <script> . . . </script> </body> </html> JavaScript DOM manipulation • Helper function appends DOM nodes for one post 14 // Append post to DOM. function updateDOM(post) { const entry = document.getElementById(''JSEntry''); const div = document.createElement(''div''); entry.appendChild(div); const t = document.createTextNode(post.owner); div.appendChild(t); const br = document.createElement(''br''); div.appendChild(br); …… } <html> <body> <div id="JSEntry"></div> <script> . . . </script> </body> </html> JavaScript DOM manipulation 16 // Append post to DOM. function updateDOM(post) { const entry = document.getElementById(''JSEntry''); const div = document.createElement(''div''); entry.appendChild(div); const t = document.createTextNode(post.owner); div.appendChild(t); const br = document.createElement(''br''); div.appendChild(br); const img = document.createElement(''img''); img.setAttribute(''src'', post.imgUrl); div.appendChild(img); } <html> <body> <div id="JSEntry"></div> <script> . . . </script> </body> </html> Memory diagram 18 function showPosts() { post1 = fetchJSONSync(".../1/"); updateDOM(post1); post2 = fetchJSONSync(".../2/"); updateDOM(post2); } Memory diagram 19 function showPosts() { post1 = fetchJSONSync(".../1/"); updateDOM(post1); post2 = fetchJSONSync(".../2/"); updateDOM(post2); } HTML Div Memory diagram 20 function showPosts() { post1 = fetchJSONSync(".../1/"); updateDOM(post1); post2 = fetchJSONSync(".../2/"); updateDOM(post2); } HTML Div Div P Image “ ….. ” “ Memory diagram 21 function showPosts() { post1 = fetchJSONSync(".../1/"); updateDOM(post1); post2 = fetchJSONSync(".../2/"); updateDOM(post2); } HTML Div Div P Image “ ….. ” “ “ Div P Image “ ….. ” “ “ Timing diagram 22 function showPosts() { post1 = fetchJSONSync(".../1/"); updateDOM(post1); post2 = fetchJSONSync(".../2/"); updateDOM(post2); } Timing diagram');
